import { useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { apiFetch } from './services/api';

export default function SectionsDocs(){
    const [sections, setSections] = useState([]);
    const [documents, setDocuments] = useState([]);
    const [selected, setSelected] = useState(null);
    const { id } = useParams();

    

    useEffect(()=>{
        (async ()=>{
            try{
                const { res, data } = await apiFetch('/api/sections');
                if(res.ok && data && data.data) setSections(data.data);
            }catch(e){ setSections([]); }
        })();
    },[]);

    useEffect(()=>{
        // if route param provided, select it; otherwise keep current
        if(id) {
            const sid = Number(id);
            if(!Number.isNaN(sid)) selectSection(sid);
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    },[id]);

    async function selectSection(sectionId){
        setSelected(sectionId);
        setDocuments([]);
        try{
            const { res, data } = await apiFetch(`/api/content/${sectionId}`);
            if(res.ok && data && data.data) setDocuments(data.data);
        }catch(e){ setDocuments([]); }
    }

    return (
        <div>
            <div className='flex flex-col md:flex-row gap-6'>
                <div className="flex flex-col gap-3 mb-4 overflow-auto md:w-1/3">
                    <div className="flex justify-between items-end">
                        <h1 className="pb-0">Secciones</h1>
                        <Link to="/upload" className="text-sm bg-amber-500 rounded hover:border p-2 mb-0 decoration-teal-500 hover:bg-teal-500 hover:bg-teal-50">Subir documento</Link>
                    </div>
                    {sections.map(s => (
                        <button key={s.pk_section}
                            className={`px-3 py-2 rounded ${selected===s.pk_section? 'bg-teal-700 text-white':'bg-teal-50'}`}
                            onClick={()=>selectSection(s.pk_section)}>
                            {s.name}
                        </button>
                    ))}
                </div>

                <div className="flex flex-col gap-3 mb-4 overflow-auto">
                    <h2 className="mb-1">Documentos</h2>
                    <div className="flex flex-wrap gap-3">
                        {documents.map(doc => (
                            <Link key={doc.pk_document} to={`/content/${doc.name}`} className="w-full bg-teal-50 p-3 rounded">
                                <h3 className="mt-0">{doc.name}</h3>
                                <p>{doc.description}</p>
                            </Link>
                        ))}
                        {documents.length === 0 && <p className="text-sm text-gray-600">Esta sección no tiene documentos.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
}
